{ title: "Koffie bestellen in Tirana", scene: "Je bent in een klein café in Tirana in de ochtend. De barista begroet je en je wilt koffie en water bestellen.", lines: [{ who: "them", sq: "Mirëmëngjes, çfarë dëshironi?", nl: "Goedemorgen, wat wilt u graag?" }, { who: "you", sq: "Mirëmëngjes, dua një kafe, ju lutem.", nl: "Goedemorgen, ik wil een koffie, alstublieft." }, { who: "them", sq: "Doni kafe të vogël apo të madhe?", nl: "Wilt u een kleine of grote koffie?" }, { who: "you", sq: "Të madhe, ju lutem.", nl: "Een grote, alstublieft." }, { who: "them", sq: "Diçka tjetër?", nl: "Nog iets anders?" }, { who: "you", sq: "Po, një ujë gjithashtu.", nl: "Ja, ook een water." }, { who: "them", sq: "Sigurisht, kushton tre euro.", nl: "Natuurlijk, het kost drie euro." }, { who: "you", sq: "A mund të paguaj me kartë?", nl: "Kan ik met kaart betalen?" }, { who: "them", sq: "Po, mundeni.", nl: "Ja, dat kan." }, { who: "you", sq: "Faleminderit shumë.", nl: "Hartelijk dank." }, { who: "them", sq: "Ju bëftë mirë.", nl: "Eet smakelijk/drink smakelijk." }] },
{ title: "Inchecken bij een hotel in Berat", scene: "Je komt aan bij een hotel in Berat. Je hebt een reservering en wilt weten of ontbijt inbegrepen is.", lines: [{ who: "them", sq: "Mirëdita, mirë se vini.", nl: "Goedendag, welkom." }, { who: "you", sq: "Mirëdita, kam një rezervim.", nl: "Goedendag, ik heb een reservering." }, { who: "them", sq: "Në çfarë emri?", nl: "Op welke naam?" }, { who: "you", sq: "Në emrin Anna de Jong.", nl: "Op naam van Anna de Jong." }, { who: "them", sq: "A mund të kem pasaportën tuaj?", nl: "Mag ik uw paspoort hebben?" }, { who: "you", sq: "Po, ja pasaporta ime.", nl: "Ja, hier is mijn paspoort." }, { who: "them", sq: "Dhoma juaj është në katin e dytë.", nl: "Uw kamer is op de tweede verdieping." }, { who: "you", sq: "Faleminderit, a ka mëngjes?", nl: "Dank u, is er ontbijt?" }, { who: "them", sq: "Po, mëngjesi është nga ora shtatë deri në dhjetë.", nl: "Ja, het ontbijt is van zeven tot tien uur." }, { who: "you", sq: "Shumë mirë, ku është ashensori?", nl: "Heel goed, waar is de lift?" }, { who: "them", sq: "Ashensori është majtas.", nl: "De lift is links." }] },
{ title: "De weg vragen naar het kasteel", scene: "Je bent in Gjirokastër en zoekt het kasteel. Je spreekt een voorbijganger aan en vraagt om eenvoudige aanwijzingen.", lines: [{ who: "you", sq: "Përshëndetje, më falni.", nl: "Hallo, excuseer mij." }, { who: "them", sq: "Po, urdhëroni.", nl: "Ja, zegt u het maar." }, { who: "you", sq: "Ku është kalaja?", nl: "Waar is het kasteel?" }, { who: "them", sq: "Kalaja është afër, shkoni drejt.", nl: "Het kasteel is dichtbij, ga rechtdoor." }, { who: "you", sq: "Pastaj majtas apo djathtas?", nl: "Daarna links of rechts?" }, { who: "them", sq: "Pastaj kthehuni djathtas.", nl: "Daarna gaat u rechtsaf." }, { who: "you", sq: "Sa minuta është?", nl: "Hoeveel minuten is het?" }, { who: "them", sq: "Rreth dhjetë minuta.", nl: "Ongeveer tien minuten." }, { who: "you", sq: "A është rruga e lehtë?", nl: "Is de weg makkelijk?" }, { who: "them", sq: "Po, por është pak përpjetë.", nl: "Ja, maar het is een beetje bergop." }, { who: "you", sq: "Faleminderit shumë.", nl: "Hartelijk dank." }, { who: "them", sq: "Mirupafshim.", nl: "Tot ziens." }] },
{ title: "Eten in een restaurant aan zee", scene: "Je zit in een restaurant in Sarandë met uitzicht op zee. Je wilt vis bestellen en vraagt wat de ober aanraadt.", lines: [{ who: "them", sq: "Mirëmbrëma, a keni rezervim?", nl: "Goedenavond, heeft u een reservering?" }, { who: "you", sq: "Jo, a keni një tavolinë për dy?", nl: "Nee, heeft u een tafel voor twee?" }, { who: "them", sq: "Po, këtu pranë detit.", nl: "Ja, hier bij de zee." }, { who: "you", sq: "Faleminderit, a keni menu në anglisht?", nl: "Dank u, heeft u een menu in het Engels?" }, { who: "them", sq: "Po, ja ku është.", nl: "Ja, hier is het." }, { who: "you", sq: "Çfarë rekomandoni?", nl: "Wat raadt u aan?" }, { who: "them", sq: "Peshku i freskët është shumë i mirë.", nl: "De verse vis is erg goed." }, { who: "you", sq: "Dua peshkun dhe një gotë verë.", nl: "Ik wil de vis en een glas wijn." }, { who: "them", sq: "Sigurisht, diçka tjetër?", nl: "Natuurlijk, nog iets anders?" }, { who: "you", sq: "Jo, faleminderit.", nl: "Nee, dank u." }, { who: "them", sq: "Shumë mirë.", nl: "Heel goed." }] },
{ title: "Een busticket kopen", scene: "Je bent bij een busstation in Tirana. Je wilt morgen naar Shkodër reizen en vraagt om een ticket.", lines: [{ who: "them", sq: "Mirëdita, ku doni të shkoni?", nl: "Goedendag, waar wilt u heen?" }, { who: "you", sq: "Dua të shkoj në Shkodër nesër.", nl: "Ik wil morgen naar Shkodër gaan." }, { who: "them", sq: "Në çfarë ore?", nl: "Om hoe laat?" }, { who: "you", sq: "Në mëngjes, ju lutem.", nl: "In de ochtend, alstublieft." }, { who: "them", sq: "Ka autobus në orën nëntë.", nl: "Er is een bus om negen uur." }, { who: "you", sq: "Sa zgjat udhëtimi?", nl: "Hoe lang duurt de reis?" }, { who: "them", sq: "Rreth dy orë.", nl: "Ongeveer twee uur." }, { who: "you", sq: "Sa kushton bileta?", nl: "Hoeveel kost het ticket?" }, { who: "them", sq: "Kushton tetë euro.", nl: "Het kost acht euro." }, { who: "you", sq: "Do ta marr.", nl: "Ik neem het." }, { who: "them", sq: "Ja bileta juaj.", nl: "Hier is uw ticket." }, { who: "you", sq: "Faleminderit.", nl: "Dank u." }] },
{ title: "Souvenirs kopen in Krujë", scene: "Je loopt door een bazaar in Krujë. Je ziet een mooie tas en vraagt naar de prijs en de kleur.", lines: [{ who: "them", sq: "Përshëndetje, a mund t’ju ndihmoj?", nl: "Hallo, kan ik u helpen?" }, { who: "you", sq: "Përshëndetje, po shikoj vetëm.", nl: "Hallo, ik kijk alleen maar." }, { who: "them", sq: "Kjo çantë është shumë e bukur.", nl: "Deze tas is erg mooi." }, { who: "you", sq: "Po, sa kushton?", nl: "Ja, hoeveel kost hij?" }, { who: "them", sq: "Kushton njëzet euro.", nl: "Hij kost twintig euro." }, { who: "you", sq: "A keni këtë në të zezë?", nl: "Heeft u deze in zwart?" }, { who: "them", sq: "Po, kemi një këtu.", nl: "Ja, we hebben er hier één." }, { who: "you", sq: "Mund ta shoh?", nl: "Mag ik hem zien?" }, { who: "them", sq: "Sigurisht.", nl: "Natuurlijk." }, { who: "you", sq: "Është shumë mirë, do ta marr.", nl: "Hij is heel goed, ik neem hem." }, { who: "them", sq: "Faleminderit.", nl: "Dank u." }] },
{ title: "Bij de apotheek", scene: "Je voelt je niet goed en gaat naar een apotheek. Je hebt hoofdpijn en vraagt of de apotheker Engels spreekt.", lines: [{ who: "them", sq: "Mirëdita, çfarë ju duhet?", nl: "Goedendag, wat heeft u nodig?" }, { who: "you", sq: "Mirëdita, a flisni anglisht?", nl: "Goedendag, spreekt u Engels?" }, { who: "them", sq: "Pak, si mund t’ju ndihmoj?", nl: "Een beetje, hoe kan ik u helpen?" }, { who: "you", sq: "Kam dhimbje koke.", nl: "Ik heb hoofdpijn." }, { who: "them", sq: "A keni temperaturë?", nl: "Heeft u koorts?" }, { who: "you", sq: "Jo, vetëm dhimbje koke.", nl: "Nee, alleen hoofdpijn." }, { who: "them", sq: "Ky ilaç mund t’ju ndihmojë.", nl: "Dit medicijn kan u helpen." }, { who: "you", sq: "Sa herë në ditë?", nl: "Hoe vaak per dag?" }, { who: "them", sq: "Dy herë në ditë, pas ushqimit.", nl: "Twee keer per dag, na het eten." }, { who: "you", sq: "Faleminderit shumë.", nl: "Hartelijk dank." }, { who: "them", sq: "Shërim të shpejtë.", nl: "Beterschap." }] },
{ title: "Smalltalk met een local", scene: "Je zit in een park in Tirana en raakt in gesprek met iemand uit de stad. Je vertelt dat je uit Nederland komt en Albanees leert.", lines: [{ who: "you", sq: "Përshëndetje, a është ky vend i lirë?", nl: "Hallo, is deze plek vrij?" }, { who: "them", sq: "Po, sigurisht.", nl: "Ja, natuurlijk." }, { who: "you", sq: "Faleminderit, jam turist.", nl: "Dank u, ik ben toerist." }, { who: "them", sq: "Nga jeni?", nl: "Waar komt u vandaan?" }, { who: "you", sq: "Jam nga Holanda.", nl: "Ik kom uit Nederland." }, { who: "them", sq: "Mirë se vini në Shqipëri.", nl: "Welkom in Albanië." }, { who: "you", sq: "Faleminderit, më pëlqen shumë Tirana.", nl: "Dank u, ik vind Tirana erg leuk." }, { who: "them", sq: "A flisni shqip?", nl: "Spreekt u Albanees?" }, { who: "you", sq: "Pak, po mësoj shqip.", nl: "Een beetje, ik leer Albanees." }, { who: "them", sq: "Shumë mirë, shqipja është e bukur.", nl: "Heel goed, Albanees is mooi." }, { who: "you", sq: "Po, por është pak e vështirë.", nl: "Ja, maar het is een beetje moeilijk." }, { who: "them", sq: "Me praktikë bëhet më e lehtë.", nl: "Met oefening wordt het makkelijker." }] }
